export class ChatGPTInputDto implements IChatGPTInputDto {
    model!: string | undefined;
    messages!: ChatGPTInputMessagesDto[] | undefined;
    temperature!: number;
    max_tokens!: number;
    top_p!: number;
    frequency_penalty!: number;
    presence_penalty!: number;

    constructor(data?: IChatGPTInputDto) {
        if (data) {
            for (var property in data) {
                if (data.hasOwnProperty(property))
                    (<any>this)[property] = (<any>data)[property];
            }
        }
    }

    init(_data?: any) {
        if (_data) {
            this.model = _data["model"];
            if (Array.isArray(_data["messages"])) {
                this.messages = [] as any;
                for (let item of _data["messages"])
                    this.messages!.push(ChatGPTInputMessagesDto.fromJS(item));
            }
            this.temperature = _data["temperature"];
            this.max_tokens = _data["max_tokens"];
            this.top_p = _data["top_p"];
            this.frequency_penalty = _data["frequency_penalty"];
            this.presence_penalty = _data["presence_penalty"];
        }
    }

    static fromJS(data: any): ChatGPTInputDto {
        data = typeof data === 'object' ? data : {};
        let result = new ChatGPTInputDto();
        result.init(data);
        return result;
    }

    toJSON(data?: any) {
        data = typeof data === 'object' ? data : {};
        data["model"] = this.model;
        if (Array.isArray(this.messages)) {
            data["messages"] = [];
            for (let item of this.messages)
                data["messages"].push(item.toJSON());
        }
        data["temperature"] = this.temperature;
        data["max_tokens"] = this.max_tokens;
        data["top_p"] = this.top_p;
        data["frequency_penalty"] = this.frequency_penalty;
        data["presence_penalty"] = this.presence_penalty;
        return data;
    }
}

export interface IChatGPTInputDto {
    model: string | undefined;
    messages: ChatGPTInputMessagesDto[] | undefined;
    temperature: number;
    max_tokens: number;
    top_p: number;
    frequency_penalty: number;
    presence_penalty: number;
}

